import React from 'react';

const Sidebar = ({ activeSection, onNavigate, userEmail, onLogout }) => {
  const menuItems = [
    { name: 'Dashboard', icon: '📊' },
    { name: 'Simulation', icon: '⚡' },
    { name: 'Detection', icon: '🛡️' },
    { name: 'Analytics', icon: '📈' },
    { name: 'Transactions', icon: '💸' },
    { name: 'Settings', icon: '⚙️' }
  ];

  return (
    <aside style={{ 
      width: '260px', 
      backgroundColor: '#0f172a', 
      padding: '1.5rem', 
      display: 'flex', 
      flexDirection: 'column',
      borderRight: '1px solid #1e293b'
    }}>
      <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginBottom: '2.5rem', paddingLeft: '0.5rem' }}>
        <div style={{ width: '32px', height: '32px', backgroundColor: '#10b981', borderRadius: '8px', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white', fontWeight: 'bold' }}>F</div>
        <h1 style={{ fontSize: '1.25rem', fontWeight: 'bold', color: 'white', margin: 0 }}>FraudShield</h1>
      </div>
      
      <nav style={{ flex: 1 }}>
        <ul style={{ listStyle: 'none', padding: 0, margin: 0 }}>
          {menuItems.map(item => (
            <li key={item.name} style={{ marginBottom: '0.5rem' }}>
              <button 
                onClick={() => onNavigate(item.name)}
                style={{ 
                  width: '100%',
                  textAlign: 'left',
                  border: 'none',
                  cursor: 'pointer',
                  color: activeSection === item.name ? '#10b981' : '#94a3b8', 
                  display: 'flex',
                  alignItems: 'center',
                  gap: '0.75rem',
                  padding: '0.75rem 1rem', 
                  borderRadius: '0.75rem', 
                  backgroundColor: activeSection === item.name ? 'rgba(16, 185, 129, 0.1)' : 'transparent',
                  transition: 'all 0.2s',
                  fontSize: '0.95rem',
                  fontWeight: activeSection === item.name ? '600' : '400'
                }}
              >
                <span style={{ fontSize: '1.1rem' }}>{item.icon}</span>
                {item.name}
              </button>
            </li>
          ))}
        </ul>
      </nav>

      <div style={{ marginTop: 'auto', padding: '1rem', backgroundColor: '#1e293b', borderRadius: '0.75rem' }}>
        <p style={{ fontSize: '0.75rem', color: '#64748b', marginBottom: '0.25rem' }}>Model Status</p>
        <p style={{ fontSize: '0.875rem', color: '#10b981', fontWeight: 'bold', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
          <span style={{ width: '8px', height: '8px', borderRadius: '50%', backgroundColor: '#10b981' }}></span>
          Operational
        </p>
      </div>
    </aside>
  );
};

export default Sidebar;
